object ExpiryAlertPolicy {
    val alertDays = listOf(7, 3, 1)

    fun shouldAlert(expiryDate: ExpiryDate, today: LocalDate): Int? {
        val daysUntil = ChronoUnit.DAYS.between(today, expiryDate.value).toInt()
        return if (daysUntil in alertDays) daysUntil else null
    }
}

