class Gifticon private constructor(
    val id: Long? = null,
    var brand: Brand,
    var productName: String,
    val imageUrl: String,
    var barcodeNumber: String,
    var expiryDate: ExpiryDate,
    var status: GifticonStatus,
    val ownerId: Long,
    val createdAt: LocalDateTime = LocalDateTime.now()
) {

override fun execute(command: MarkViewedUseCase.Command) {
    if (!sharedGifticonPort.isSharedWithUser(command.gifticonId, command.userId)) {
        throw GifticonAccessDeniedException()
    }
    val existing = viewMarkRepositoryPort.findByGifticonIdAndUserId(command.gifticonId, command.userId)
    if (existing == null) {
        viewMarkRepositoryPort.save(
            ViewMark(gifticonId = command.gifticonId, userId = command.userId)
        )
    }
}

override fun share(gifticonId: Long, groupId: Long) {
    val existing = sharedGifticonJpaRepository.findByGifticonIdAndGroupId(gifticonId, groupId)
    if (existing == null) {
        sharedGifticonJpaRepository.save(
            SharedGifticonJpaEntity(gifticonId = gifticonId, groupId = groupId)
        )
    }
}

companion object {
    fun from(result: RegisterGifticonUseCase.Result): GifticonResponse {
        val daysUntilExpiry = result.expiryDate?.let {
            runCatching {
                ChronoUnit.DAYS.between(LocalDate.now(), LocalDate.parse(it))
            }.getOrNull()
        }
        return GifticonResponse(..., daysUntilExpiry = daysUntilExpiry)
    }
}

